mapper.select:
SELECT o.id,o.order_no,o.shop_id,shop.`name` as shopname,o.total_amount,o.pay_amount,o.discount_amount,o.`status`,o.create_time,o.pay_time,o.finish_time,o.cancel_time,o.order_type,o.pay_type
FROM `order` o
INNER JOIN shop ON o.shop_id=shop.id
WHERE o.user_id = #{userId}

  AND ${ew.customSqlSegment.replace('WHERE','')}

SELECT o.id,o.order_no,shop.`name` as shopname,o.total_amount,o.pay_amount,o.discount_amount,o.`status`,o.create_time,o.pay_time,o.finish_time,o.cancel_time,o.order_type,o.pay_type
FROM `order` o
INNER JOIN shop ON o.shop_id=shop.id


        AND o.status = #{params.status}


        AND o.user_id = #{params.userId}


        AND shop.name LIKE CONCAT('%', #{params.shopname}, '%')


        AND o.total_amount >= #{params.minAmount}


        AND o.total_amount <= #{params.maxAmount}


        AND o.create_time >= #{params.startTime}


        AND o.create_time <= #{params.endTime}


ORDER BY o.create_time DESC
